    if not isinstance(n, int) or not isinstance(b, int):
        raise ValueError("Inputs must be integers.")
    if n < 0:
        raise ValueError("n must be a non-negative integer.")
    if b < 2 or b > 16:
        raise ValueError("b must be between 2 and 16 inclusive.")

