def to_base(n, b):
    if n == "" or n == []:
        return ""
    if b < 2 or b > 16:
        raise ValueError("Base must be between 2 and 16")
    if n < 0:
        raise ValueError("n must be a non-negative integer")
    if n == 0:
        return "0"

    chars = "0123456789abcdef"
    digits = []
    while n > 0:
        rem = n % b
        digits.append(chars[rem])
        n = n // b

    return "".join(reversed(digits))

def rle_encode(s: str) -> str:
    if not s:
        return ""

    result = []
    current_char = s[0]
    count = 0

    for c in s:
        if c == current_char:
            count += 1
        else:
            result.append(f"{current_char.lower()}{count}")
            current_char = c
            count = 1

    result.append(f"{current_char.lower()}{count}")

    return "".join(result)

def rle_encode(s: str) -> str:
    if not s:
        return ""

    result = []
    count = 1

    for i in range(1, len(s)):
        if s[i] == s[i - 1]:
            count += 1
        else:
            result.append(s[i - 1] + str(count))
            count = 1

    result.append(s[-1] + str(count))

    return "".join(result)

def roman_to_int(s: str) -> int:
    if not s:
        return 0

    roman_values = {
        'I': 1, 'V': 5, 'X': 10, 'L': 50,
        'C': 100, 'D': 500, 'M': 1000
    }

    total = 0
    prev_value = 0

    for char in reversed(s):
        if char not in roman_values:
            raise ValueError(f"Invalid Roman numeral character: {char}")
        value = roman_values[char]
        if value < prev_value:
            total -= value
        else:
            total += value
        prev_value = value

    return total

